script.text:
      /* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g._$trongso = g._getColumnOrder('trong_so');
  g._$diem_nv_dg = g._getColumnOrder('diem_nv_dg');
  g._$diem_ql_dg = g._getColumnOrder('diem_ql_dg');
  g._$stt0 = g._getColumnOrder('stt0');
  g._$stt = g._getColumnOrder('stt');
}
function dispose$GridVoucherDetail$(g) {
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}

function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
     case 'Retrieve':
      if (f._action == 'View') break;
      if (!f.validFields('ma_ky')) break;
      if (!f.validFields('nam')) break;
		  if (!f.validFields('ma_nv')) break;

      on$Filter$QueryComplete(g, f.getItemValue('ma_ky'), f.getItemValue('nam'), f.getItemValue('stt_rec_nv'));
      f.setItemValues('t_diem_nv_dg, t_diem_ql_dg', [0, 0]);
      break;
    default:
      break;
  }
}

function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'diem_nv_dg':
    case 'diem_ql_dg':
      var a = g._getItemValue(g._activeRow, g._$stt0);
      if (a == '') a = g._getItemValue(g._activeRow, g._$stt);
      onChange$Grid$SelfScore$(g, f, a, g._activeColumn);
      break;
    default:
      break;
  }
}

function onChange$Grid$SelfScore$(g, f, a, col) {
  var weight = 0, total = 0, val = 0, add = 1;
  for (var i = 1; i <= g._rowCount; i++) {
    if (g._getItemValue(i, g._$stt) == a) {
      add = i;
      break;
    }
  }
  if (add == g._activeRow) {
    onChange$Grid$Total(g, f, col);
    return;
  }

  for (var r = 1; r <= g._rowCount; r++) {
    if (g._getItemValue(r, g._$stt0) == a) {
      weight += g._getItemValue(r, g._$trongso);
      total += g._getItemValue(r, col) * g._getItemValue(r, g._$trongso);
    }
  }

  val = weight == 0 ? 0 : total / weight;
	g._setItemValue(add, col, val);
  onChange$Grid$Total(g, f, col);
}

function onChange$Grid$Total(g, f, col) {
  var weight = 0, total = 0, val = 0;
  for (var i = 1; i <= g._rowCount; i++) {
    if (g._getItemValue(i, g._$stt0) == '') {
      weight += g._getItemValue(i, g._$trongso);
      total += g._getItemValue(i, col) * g._getItemValue(i, g._$trongso)
    }
  }
  val = weight == 0 ? 0 : total / weight;
  f.setItemValue(((col == g._$diem_nv_dg) ? 't_diem_nv_dg' : 't_diem_ql_dg'), val);
}

function on$Filter$QueryComplete(g, a, b, c) {
  var k = [];
  Array.add(k, {Name: 'ma_ky', OldValue: null, NewValue: parseInt(a), Modified: true, Items: []});
  Array.add(k, {Name: 'nam', OldValue: null, NewValue: b, Modified: true, Items: []});
  Array.add(k, {Name: 'key_nv', OldValue: null, NewValue: c, Modified: true, Items: []});
  g.set_memvars(k);
  g.set_gridPageIndex(-2);
  g._loadPage(1);

  var o = g.get_element().field;
  o.AllowContain = true;
  o.FilterSource = '';
}
/* </flatten> */
